import { supabase, ENV } from './supabaseClient.js';

const IMGS = ['data:image/jpeg;base64,', 'data:image/jpeg;base64,', 'data:image/jpeg;base64,', 'data:image/jpeg;base64,', 'data:image/jpeg;base64,', 'data:image/jpeg;base64,', 'data:image/jpeg;base64,', 'data:image/jpeg;base64,', 'data:image/jpeg;base64,'];
const FALLBACK_PRODUCTS = [
  {id:1,name:"Dark Brown Crewneck Set",cat:"sets",price:9500,sizes:["S","M","L","XL","XXL"],colors:["Dark Brown","Espresso"],desc:"Crewneck + wide-leg sweatpant. Heavyweight fleece. Signature silhouette.",tags:["flagship","new"],img:IMGS[0]},
  {id:2,name:"Brown Hoodie Wide-Leg Set",cat:"sets",price:9500,sizes:["S","M","L","XL","XXL"],colors:["Dark Brown"],desc:"Oversized hoodie + wide-leg pants. The ultimate matching set.",tags:["flagship","new"],img:IMGS[6]},
  {id:3,name:"Camel Hoodie & Shorts Set",cat:"sets",price:8500,sizes:["XS","S","M","L","XL"],colors:["Camel","Sand"],desc:"Oversized hoodie with matching shorts. Signature camel colourway.",tags:["new","bestseller"],img:IMGS[3]},
  {id:4,name:"Black Oversized Hoodie",cat:"sweatshirts",price:5200,sizes:["S","M","L","XL","XXL"],colors:["Black","Dark Brown"],desc:"Premium oversized pullover hoodie. House of Brené signature chest logo.",tags:["new"],img:IMGS[4]},
  {id:5,name:"Camel Off-Shoulder Sweatshirt",cat:"sweatshirts",price:4800,sizes:["XS","S","M","L","XL"],colors:["Camel"],desc:"Off-shoulder cropped sweatshirt. Statement silhouette, premium fleece.",tags:["limited"],img:IMGS[5]},
  {id:6,name:"Brown Crewneck Sweatshirt",cat:"sweatshirts",price:4200,sizes:["XS","S","M","L","XL","XXL"],colors:["Dark Brown","Espresso"],desc:"Boxy drop-shoulder crewneck. Tonal embroidered logo. Essential piece.",tags:["new"],img:IMGS[2]},
  {id:7,name:"Dark Brown Wide-Leg Sweatpant",cat:"sweatpants",price:4800,sizes:["XS","S","M","L","XL","XXL"],colors:["Dark Brown","Black"],desc:"Premium wide-leg fleece jogger. Drawstring waist, logo embroidery.",tags:["flagship"],img:IMGS[7]},
  {id:8,name:"Camel Fleece Shorts",cat:"sweatpants",price:3200,sizes:["XS","S","M","L","XL"],colors:["Camel","Sand"],desc:"Premium fleece shorts with drawstring. Co-ords perfectly with the camel hoodie.",tags:[],img:IMGS[5]},
];
const COLORS = {["Dark Brown"]:"#2a1a0a","Black":"#0a0a0a",Espresso:"#3a2210",Camel:"#c8a84a",Sand:"#d4c8a8"};
let PRODS = [...FALLBACK_PRODUCTS];
let cart=[],selSizes={},ordQty=1,ordSz='',curStep=1;

function mapCatalogueRow(row, index){
  return {
    id: row.id || index + 1,
    name: row.name,
    cat: row.category || 'sets',
    price: Number(row.price || 0),
    sizes: row.sizes && row.sizes.length ? row.sizes : ['S','M','L','XL'],
    colors: row.colors && row.colors.length ? row.colors : ['Black'],
    desc: row.description || '',
    tags: row.tags && row.tags.length ? row.tags : [],
    img: row.image_url || IMGS[index % IMGS.length],
    in_stock: row.in_stock !== false
  };
}

async function fetchCatalogue(){
  if(!ENV.SUPABASE_URL || !ENV.SUPABASE_ANON_KEY) return [];
  const { data, error } = await supabase.from('catalogue').select('*').eq('in_stock', true).order('created_at', { ascending:false });
  if(error) throw error;
  return (data || []).map(mapCatalogueRow);
}
// ── CART ──
function cartTotal(){return cart.reduce((s,i)=>s+i.price*i.qty,0)}
function cartCount(){return cart.reduce((s,i)=>s+i.qty,0)}
function updCartUI(){
  const cnt=cartCount(),badge=document.getElementById('cart-badge');
  badge.textContent=cnt; badge.style.display=cnt>0?'flex':'none';
  document.getElementById('ch-count').textContent=cnt+' '+(cnt===1?'item':'items');
  document.getElementById('cf-total').textContent='KES '+cartTotal().toLocaleString();
  const el=document.getElementById('cart-items'),em=document.getElementById('cart-empty');
  if(cart.length===0){em.style.display='flex';el.innerHTML='';return;}
  em.style.display='none';
  el.innerHTML=cart.map(i=>`<div class="ci">
    <div class="ci-thumb"><img src="${i.img}" alt="${i.name}"/></div>
    <div style="flex:1;min-width:0">
      <div class="ci-name">${i.name}</div>
      <div class="ci-meta">${i.size} · ${i.color}</div>
      <div class="ci-price">KES ${i.price.toLocaleString()}</div>
      <div class="ci-acts">
        <div class="ci-qty">
          <button onclick="updQty('${i.key}',-1)">−</button>
          <span>${i.qty}</span>
          <button onclick="updQty('${i.key}',1)">+</button>
        </div>
        <button class="ci-rm" onclick="rmItem('${i.key}')">Remove</button>
      </div>
    </div>
  </div>`).join('');
  updOS();
}
function addCart(id,size,color){
  const p=PRODS.find(x=>x.id===id); if(!p) return;
  const key=`${id}-${size}-${color}`,ex=cart.find(i=>i.key===key);
  if(ex){ex.qty++;}else{cart.push({...p,size,color,qty:1,key});}
  updCartUI(); showToast(p.name+' (${size}) added to bag'); toggleCart(true);
}
function updQty(key,d){
  const it=cart.find(i=>i.key===key); if(!it) return;
  it.qty+=d; if(it.qty<1) cart=cart.filter(i=>i.key!==key);
  updCartUI();
}
function rmItem(key){cart=cart.filter(i=>i.key!==key);updCartUI();}
function toggleCart(fo){
  const d=document.getElementById('cart-drawer'),o=document.getElementById('cart-ov'),isO=d.classList.contains('open');
  if(fo===true||!isO){d.classList.add('open');o.classList.add('show');}
  else{d.classList.remove('open');o.classList.remove('show');}
}

// ── PRODUCTS GRID ──
function renderProds(filter){
  if(!Array.isArray(PRODS)||PRODS.length===0){ document.getElementById('prod-grid').innerHTML='<div style="grid-column:1/-1;color:var(--ash);padding:1rem 0">No catalogue items available yet.</div>'; return; }
  const g=document.getElementById('prod-grid');
  const list=!filter||filter==='all'?PRODS:PRODS.filter(p=>p.cat===filter);
  g.innerHTML=list.map(p=>`
    <div class="pc" data-id="${p.id}">
      <div class="pc-img">
        <img src="${p.img}" alt="${p.name}" loading="lazy"/>
        <div class="pc-tags">
          ${p.tags.includes('new')?'<span class="tag tnew">New</span>':''}
          ${p.tags.includes('flagship')?'<span class="tag tflag">Flagship</span>':''}
          ${p.tags.includes('limited')?'<span class="tag tlim">Limited</span>':''}
          ${p.tags.includes('bestseller')?'<span class="tag tbs">Best Seller</span>':''}
        </div>
        <div class="qa">
          <div class="sz-row">
            ${p.sizes.map(s=>`<button class="sz" onclick="selSz(${p.id},'${s}',this)">${s}</button>`).join('')}
          </div>
          <button class="atb" id="ab-${p.id}" disabled onclick="quickAdd(${p.id})">Select Size</button>
        </div>
      </div>
      <div class="pc-info">
        <div class="pc-row">
          <div class="pc-name">${p.name}</div>
          <div class="pc-price">KES ${p.price.toLocaleString()}</div>
        </div>
        <div class="pc-desc">${p.desc}</div>
        <div class="cdots">${p.colors.map(c=>`<div class="cdot" style="background:${COLORS[c]||'#444'}" title="${c}"></div>`).join('')}</div>
      </div>
    </div>`).join('');
  setTimeout(()=>{document.querySelectorAll('.pc').forEach(el=>obs.observe(el));},80);
}
function selSz(id,s,btn){
  selSizes[id]=s;
  btn.closest('.pc').querySelectorAll('.sz').forEach(b=>b.classList.remove('sel'));
  btn.classList.add('sel');
  const ab=document.getElementById('ab-'+id);
  ab.disabled=false; ab.textContent='Add to Bag';
}
function quickAdd(id){
  const s=selSizes[id]; if(!s) return;
  const p=PRODS.find(x=>x.id===id);
  addCart(id,s,p.colors[0]);
  selSizes[id]=null;
  const ab=document.getElementById('ab-'+id);
  ab.textContent='✓ Added!'; ab.disabled=true;
  setTimeout(()=>{ab.textContent='Select Size';document.getElementById('ab-'+id).closest('.pc').querySelectorAll('.sz').forEach(b=>b.classList.remove('sel'));},2000);
}
function fp(cat,btn){
  document.querySelectorAll('.fb').forEach(b=>b.classList.remove('active'));
  btn.classList.add('active'); renderProds(cat);
}

// ── ORDER ──
function getOI(){
  if(cart.length>0) return cart;
  const pn=document.getElementById('fprod').value; if(!pn) return [];
  const p=PRODS.find(x=>x.name===pn); if(!p) return [];
  return [{...p,size:ordSz||p.sizes[0],color:p.colors[0],qty:ordQty}];
}
function gst(step){
  if(step>curStep){
    if(curStep===1){
      if(!document.getElementById('fn').value.trim()){showToast('Please enter your name');return;}
      if(!document.getElementById('fe').value.match(/^[^@]+@[^@]+\.[^@]+$/)){showToast('Please enter a valid email');return;}
      if(!document.getElementById('fp_').value.trim()){showToast('Please enter your phone number');return;}
      if(!document.getElementById('fa').value.trim()){showToast('Please enter your delivery address');return;}
    }
    if(curStep===2&&getOI().length===0){showToast('Please add items to your order');return;}
  }
  document.getElementById('fp'+curStep).classList.remove('active');
  const stEl=document.getElementById('st'+curStep);
  stEl.classList.remove('active');
  if(step>curStep) stEl.classList.add('done');
  curStep=step;
  document.getElementById('fp'+curStep).classList.add('active');
  document.getElementById('st'+curStep).classList.add('active');
  if(curStep===2) rendS2();
  if(curStep===3) rendS3();
}
function rendS2(){
  const coi=document.getElementById('cart-order-items'),ms=document.getElementById('manual-sec');
  if(cart.length>0){
    ms.style.display='none';
    coi.innerHTML=`<div style="font-size:.58rem;letter-spacing:.18em;text-transform:uppercase;color:var(--ash);margin-bottom:.9rem">Items in your bag</div>`+
      cart.map(i=>`<div style="display:flex;justify-content:space-between;padding:.65rem 0;border-bottom:1px solid var(--graphite)">
        <div><div style="font-size:.7rem;color:var(--pearl);text-transform:uppercase;letter-spacing:.05em">${i.name}</div><div style="font-size:.62rem;color:var(--ash);margin-top:2px">${i.size} · ${i.color} · Qty ${i.qty}</div></div>
        <div style="font-family:var(--font-display);color:var(--taupe);font-size:.9rem">KES ${(i.price*i.qty).toLocaleString()}</div>
      </div>`).join('')+
      `<div style="display:flex;justify-content:space-between;padding-top:.9rem">
        <span style="font-size:.58rem;letter-spacing:.18em;text-transform:uppercase;color:var(--ash)">Total</span>
        <span style="font-family:var(--font-display);color:var(--pearl);font-size:1.2rem">KES ${cartTotal().toLocaleString()}</span>
      </div>`;
  }else{
    ms.style.display='block'; coi.innerHTML='';
    const sel=document.getElementById('fprod');
    if(sel.options.length<=1) PRODS.forEach(p=>{const o=document.createElement('option');o.value=p.name;o.textContent=`${p.name} — KES ${p.price.toLocaleString()}`;sel.appendChild(o);});
  }
  updOS();
}
function updProd(){
  if(!Array.isArray(PRODS)||PRODS.length===0) return;
  const pn=document.getElementById('fprod').value,p=PRODS.find(x=>x.name===pn);
  const sf=document.getElementById('sz-fld'),cf=document.getElementById('col-fld');
  if(!p){sf.style.display='none';cf.style.display='none';return;}
  sf.style.display='block'; cf.style.display='block';
  document.getElementById('ord-sizes').innerHTML=p.sizes.map(s=>`<button class="spb" onclick="selOrdSz('${s}',this)">${s}</button>`).join('');
  document.getElementById('fcol').innerHTML=p.colors.map(c=>`<option value="${c}">${c}</option>`).join('');
  ordSz=''; updOS();
}
function selOrdSz(s,btn){ordSz=s;document.querySelectorAll('.spb').forEach(b=>b.classList.remove('active'));btn.classList.add('active');updOS();}
function chQty(d){ordQty=Math.max(1,ordQty+d);document.getElementById('qty-v').textContent=ordQty;updOS();}
function updOS(){
  const items=getOI(),total=items.reduce((s,i)=>s+i.price*(i.qty||1),0);
  const el=document.getElementById('os-items');
  el.innerHTML=items.length===0?'<div class="os-empty">Your bag is empty</div>':
    items.map(i=>`<div class="os-item"><div><div class="os-name">${i.name}</div><div class="os-det">${i.size||''} · Qty ${i.qty||1}</div></div><div class="os-price">KES ${(i.price*(i.qty||1)).toLocaleString()}</div></div>`).join('');
  document.getElementById('os-total').textContent='KES '+total.toLocaleString();
}
function rendS3(){
  const items=getOI(),total=items.reduce((s,i)=>s+i.price*(i.qty||1),0);
  document.getElementById('pay-sum-items').innerHTML=items.map(i=>`<div style="display:flex;justify-content:space-between;padding:.45rem 0;border-bottom:1px solid var(--steel);font-size:.68rem"><span style="color:var(--pearl)">${i.name} (${i.size||''}) ×${i.qty||1}</span><span style="color:var(--taupe)">KES ${(i.price*(i.qty||1)).toLocaleString()}</span></div>`).join('');
  document.getElementById('pay-total').textContent='KES '+total.toLocaleString();
  const ph=document.getElementById('fp_').value;
  document.getElementById('mpesa-ph').textContent=ph||'your phone';
  document.getElementById('stk-b').textContent=`Send M-Pesa Prompt · KES ${total.toLocaleString()}`;
}
async function sendSTK(){
  const btn=document.getElementById('stk-b');
  const phone=document.getElementById('fp_').value.trim();
  const amount=getOI().reduce((s,i)=>s+i.price*(i.qty||1),0);
  if(!phone){showToast('Please enter your phone number first');return;}
  if(amount<1){showToast('Add an item before requesting payment');return;}
  btn.textContent='Sending...'; btn.disabled=true;
  try{
    const res=await fetch(`${ENV.MPESA_API_BASE}/api/mpesa/pay`,{
      method:'POST',headers:{'Content-Type':'application/json'},
      body:JSON.stringify({phone,amount,accountReference:'HOUSE-OF-BRENE',transactionDesc:'House of Brene order'})
    });
    const data=await res.json();
    if(!res.ok) throw new Error(data.error||'Failed to send STK prompt');
    document.getElementById('mpesa-cr').classList.add('show');
    btn.style.display='none';
    showToast(data.customerMessage||'M-Pesa prompt sent!');
  }catch(err){
    btn.textContent=`Send M-Pesa Prompt · KES ${amount.toLocaleString()}`;
    btn.disabled=false;
    showToast(err.message||'Unable to send M-Pesa prompt');
  }
}
async function placeOrd(){
  const btn=document.getElementById('place-btn');
  btn.textContent='Placing order...'; btn.disabled=true;
  try{
    const fullName=document.getElementById('fn').value.trim();
    const email=document.getElementById('fe').value.trim();
    const phone=document.getElementById('fp_').value.trim();
    const items=getOI();
    if(items.length===0) throw new Error('Your order is empty');

    const customerPayload={name:fullName,email,phone};
    let customerId=null;
    const { data: existingCustomers, error: customerLookupError } = await supabase
      .from('customers')
      .select('id')
      .or(`email.eq.${email},phone.eq.${phone}`)
      .limit(1);
    if(customerLookupError) throw customerLookupError;
    if(existingCustomers && existingCustomers.length){
      customerId=existingCustomers[0].id;
      const { error:updateCustomerError } = await supabase.from('customers').update(customerPayload).eq('id',customerId);
      if(updateCustomerError) throw updateCustomerError;
    } else {
      const { data:newCustomer, error:createCustomerError } = await supabase.from('customers').insert(customerPayload).select('id').single();
      if(createCustomerError) throw createCustomerError;
      customerId=newCustomer.id;
    }

    const paymentCode=(document.getElementById('fmpesa').value||'').trim().toUpperCase();
    const orderRows=items.map(item=>({customer_id:customerId,product_name:item.name,size:item.size||null,quantity:item.qty||1,total_price:(item.price*(item.qty||1)),payment_status:paymentCode?`paid:${paymentCode}`:'pending'}));
    const { data: insertedOrders, error: orderError } = await supabase.from('orders').insert(orderRows).select('id');
    if(orderError) throw orderError;
    const oid=`HOB-${String(insertedOrders[0].id).slice(0,8).toUpperCase()}`;

    document.getElementById('fp3').classList.remove('active');
    document.querySelectorAll('.fst').forEach(s=>s.classList.remove('active','done'));
    const suc=document.getElementById('ord-suc'); suc.classList.add('show');
    document.getElementById('suc-id').textContent=oid;
    document.getElementById('suc-email').textContent=email;
    cart=[]; updCartUI(); updOS(); showToast('Order placed!');
  }catch(err){
    console.error(err);
    showToast(err.message||'Could not place your order');
    btn.textContent='Place Order →'; btn.disabled=false;
    return;
  }
}

// ── CONTACT ──
function subContact(){
  const n=document.getElementById('cn').value.trim(),e=document.getElementById('ce').value.trim(),m=document.getElementById('cm').value.trim();
  if(!n||!e||!m){showToast('Please fill in all required fields');return;}
  document.getElementById('ct-form').style.display='none';
  document.getElementById('ct-suc').style.display='block';
}

// ── NEWSLETTER ──
function subNL(e){e.preventDefault();document.getElementById('nl-wrap').innerHTML=`<p style="font-family:var(--font-display);font-style:italic;color:var(--taupe);font-size:1.05rem">You're in. Welcome to the family ✓</p>`;}

// ── CURSOR ──
const cur=document.getElementById('cur'),curR=document.getElementById('cur-r');
let cx=0,cy=0,rx=0,ry=0;
document.addEventListener('mousemove',e=>{cx=e.clientX;cy=e.clientY;cur.style.left=cx+'px';cur.style.top=cy+'px';});
setInterval(()=>{rx+=(cx-rx)*.14;ry+=(cy-ry)*.14;curR.style.left=rx+'px';curR.style.top=ry+'px';},16);

// ── NAV SCROLL ──
window.addEventListener('scroll',()=>{document.getElementById('nav').classList.toggle('scrolled',window.scrollY>40);});

// ── MOBILE NAV ──
function toggleMob(){
  const n=document.getElementById('mob-nav'),h=document.getElementById('ham'),o=n.classList.toggle('open');
  const s=h.querySelectorAll('span');
  if(o){s[0].style.transform='rotate(45deg) translate(4px,4px)';s[1].style.opacity='0';s[2].style.transform='rotate(-45deg) translate(4px,-4px)';}
  else{s[0].style.transform='';s[1].style.opacity='';s[2].style.transform='';}
}

// ── SCROLL REVEAL ──
const obs=new IntersectionObserver(entries=>{entries.forEach(e=>{if(e.isIntersecting) e.target.classList.add('vis');});},{threshold:.08,rootMargin:'0px 0px -30px 0px'});
document.querySelectorAll('.rv').forEach(el=>obs.observe(el));

// ── TOAST ──
function showToast(msg){const t=document.getElementById('toast');t.textContent=msg;t.classList.add('show');setTimeout(()=>t.classList.remove('show'),3000);}

// ── INIT ──
async function boot(){
  try{
    const remoteProducts=await fetchCatalogue();
    if(remoteProducts.length){ PRODS.splice(0,PRODS.length,...remoteProducts); }
  }catch(err){ console.warn('Using embedded catalogue fallback', err); }
  renderProds('all');
  updOS();
}
boot();
